module RefModule (
    input signed [3:0] k,
    input signed [3:0] l,
    output signed [3:0] m
);

    // Perform addition
      wire _n01 = k[0] ^ l[0];
  wire _c01 = k[0] & l[0];
  wire _n02 = k[1] ^ l[1] ^ _c01;
  wire _c02 = (k[1] & l[1]) | (k[1] & _c01) | (l[1] & _c01);
  wire _n03 = k[2] ^ l[2] ^ _c02;
  wire _c03 = (k[2] & l[2]) | (k[2] & _c02) | (l[2] & _c02);
  wire _n04 = k[3] ^ l[3] ^ _c03;
  wire _c04 = (k[3] & l[3]) | (k[3] & _c03) | (l[3] & _c03);
  assign m = {_n01, _n02, _n03, _n04};

endmodule
